// src/lib/plugin.ts
var plugin = (def) => ({
  strict: false,
  alwaysApply: false,
  ...def,
  apply: (cldAsset, ctx) => def.apply(cldAsset, ctx, ctx)
});

// src/plugins/enhance.ts
var EnhancePlugin = /* @__PURE__ */ plugin({
  name: "Enhance",
  supports: "image",
  inferOwnOptions: {},
  props: {
    enhance: true
  },
  apply: (cldAsset, opts) => {
    if (opts.enhance) {
      cldAsset.addTransformation("e_enhance");
    }
    return {};
  }
});
export {
  EnhancePlugin
};
